import React, { useState } from "react";
import {
  GoogleMap,
  LoadScript,
  DirectionsService,
  DirectionsRenderer
} from "@react-google-maps/api";

const containerStyle = {
  width: "100%",
  height: "400px"
};

function Map({ origin, destination }) {

  const [directions, setDirections] = useState(null);

  const callback = (response) => {
    if (response !== null && response.status === "OK") {
      setDirections(response);
    }
  };

  return (

    <LoadScript googleMapsApiKey="YOUR_GOOGLE_API_KEY">

      <GoogleMap
        mapContainerStyle={containerStyle}
        center={{ lat: 25.5941, lng: 85.1376 }}
        zoom={13}
      >

        {origin && destination && (

          <DirectionsService
            options={{
              origin: origin,
              destination: destination,
              travelMode: "DRIVING"
            }}
            callback={callback}
          />

        )}

        {directions && (

          <DirectionsRenderer
            options={{
              directions: directions
            }}
          />

        )}

      </GoogleMap>

    </LoadScript>

  );
}

export default Map;
